func TestNetworkSim_Convergence(t *testing.T) {
	ns := NewNetworkSim(42)
	for i := 0; i < 5; i++ {
		nodeID := fmt.Sprintf("n%d", i)
		ns.AddNode(nodeID, 2)
	}

	// Each node writes unique data
